#include <stdlib.h>
#include <string.h>

#define INITIAL_SIZE 10

typedef struct Node {
    char *key;
    int value;
    struct Node *next;
} Node;

typedef struct {
    Node **buckets;
    int size;
} Dictionary;

Dictionary* createDictionary() {
    Dictionary *dict = (Dictionary *)malloc(sizeof(Dictionary));
    dict->size = INITIAL_SIZE;
    dict->buckets = (Node **)malloc(INITIAL_SIZE * sizeof(Node *));
    for (int i = 0; i < INITIAL_SIZE; i++) {
        dict->buckets[i] = NULL;
    }
    return dict;
}

unsigned int hashFunction(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = (hash << 5) + *key++;
    }
    return hash % INITIAL_SIZE;
}

void insert(Dictionary *dict, const char *key, int value) {
    unsigned int index = hashFunction(key);
    Node *newNode = (Node *)malloc(sizeof(Node));
    newNode->key = strdup(key);
    newNode->value = value;
    newNode->next = dict->buckets[index];
    dict->buckets[index] = newNode;
}

